custom_css:
/* ✦ Midnight Prism ✦ */

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   FONTS & VARIABLES
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
@import url('https://fonts.googleapis.com/css2?family=Varela+Round&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Fredoka:wght@600&display=swap');

:root {
  --white30a: rgba(175, 135, 210, 0.8);
  --white50a: rgba(195, 155, 230, 0.9);
}

#sheld {
  background-color: #0a0514 !important;
}

body, .mes_text, textarea, input, select, button {
  font-family: 'Varela Round', sans-serif !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   CHAT AREA
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
#chat {
  padding: 16px 16px !important;
  border-top: 4px solid transparent !important;
  border-image: linear-gradient(to right, rgba(60, 30, 80, 1), rgba(40, 28, 85, 1), rgba(24, 40, 85, 1)) 1 !important;
  margin: 0 !important;
  background-image: radial-gradient(circle, rgba(255, 255, 255, 0.1) 1px, transparent 1px) !important;
  background-size: 8px 8px !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   MESSAGE BUBBLES
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* Base bubble */
.mes {
  position: relative !important;
  border-radius: 20px !important;
  padding: 14px 20px 16px 20px !important;
  margin-bottom: 14px !important;
  border: 3px solid rgba(130, 100, 195, 0.5) !important;
  box-shadow:
    0 3px 14px rgba(80, 50, 150, 0.35),
    inset 0 1px 0 rgba(255, 255, 255, 0.05) !important;
}

/* Character bubble — left side */
.mes[is_user="false"] {
  padding-left: 70px !important;
  position: relative !important;
  background: linear-gradient(
    to bottom,
    rgba(100, 150, 255, 0.18) 0px,
    rgba(100, 150, 255, 0.18) 0px,
    rgba(16, 12, 40, 0.97) 0px,
    rgba(14, 18, 48, 0.97) 100%
  ) !important;
  border-color: rgba(110, 155, 245, 0.35) !important;
  box-shadow:
    0 3px 14px rgba(70, 100, 210, 0.2),
    inset 0 1px 0 rgba(255, 255, 255, 0.05) !important;
}
.mes[is_user="false"] .mesAvatarWrapper {
  position: absolute !important;
  top: 12px !important;
  left: 12px !important;
  right: auto !important;
}
.mes[is_user="false"] .mes_block {
  margin-left: 0 !important;
  margin-right: 0 !important;
}

/* User bubble — right side */
.mes[is_user="true"] {
  padding-right: 54px !important;
  position: relative !important;
  flex-direction: row-reverse;
  margin-left: auto;
  background: linear-gradient(
    to bottom,
    rgba(255, 110, 180, 0.18) 0px,
    rgba(255, 110, 180, 0.18) 0px,
    rgba(34, 10, 36, 0.97) 0px,
    rgba(38, 14, 40, 0.97) 100%
  ) !important;
  border-color: rgba(210, 130, 195, 0.35) !important;
  box-shadow:
    0 3px 14px rgba(170, 70, 155, 0.2),
    inset 0 1px 0 rgba(255, 255, 255, 0.05) !important;
}
.mes[is_user="true"] .mesAvatarWrapper {
  position: absolute !important;
  top: 12px !important;
  right: 12px !important;
  left: auto !important;
}
.mes[is_user="true"] .mes_block {
  margin-left: 0 !important;
  margin-right: 0 !important;
}

/* User name header flex fixes */
.mes[is_user="true"] .mes_block .ch_name.flex-container.justifySpaceBetween {
  flex-direction: row-reverse;
  margin-left: auto;
}
.mes[is_user="true"] .mes_block .ch_name.flex-container.justifySpaceBetween .flex-container.flex1.alignitemscenter {
  flex-direction: row-reverse;
}
.mes[is_user="true"] .mes_block .ch_name.flex-container.justifySpaceBetween .flex-container.flex1.alignitemscenter .flex-container.alignItemsBaseline {
  flex-direction: row-reverse;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   MESSAGE TEXT
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* Base text */
.mes_text,
.mes_text p,
.mes_text em,
.mes_text strong {
  text-align: center !important;
  text-shadow: none !important;
  color: #e1d7f5 !important;
  line-height: 1.8 !important;
  letter-spacing: 0.01em !important;
}

/* Character text formatting */
.mes[is_user="false"] .mes_text q,
.mes[is_user="false"] .mes_text blockquote { color: rgba(232, 138, 178, 1) !important; }
.mes[is_user="false"] .mes_text em { color: rgba(140, 185, 230, 1) !important; }
.mes[is_user="false"] .mes_text strong em,
.mes[is_user="false"] .mes_text em strong { color: rgba(200, 155, 235, 1) !important; }
.mes[is_user="false"] .mes_text u { color: rgba(140, 185, 230, 1) !important; }

/* User text formatting */
.mes[is_user="true"] .mes_text q,
.mes[is_user="true"] .mes_text blockquote { color: rgba(140, 185, 230, 1) !important; }
.mes[is_user="true"] .mes_text em { color: rgba(232, 138, 178, 1) !important; }
.mes[is_user="true"] .mes_text strong em,
.mes[is_user="true"] .mes_text em strong { color: rgba(200, 155, 235, 1) !important; }
.mes[is_user="true"] .mes_text u { color: rgba(232, 138, 178, 1) !important; }

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   NAMES
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
.ch_name .name_text {
  display: none !important;
}

/* Character name */
.mes::after {
  font-family: 'Fredoka', sans-serif !important;
  content: '✦ ' attr(ch_name) ' ✦' !important;
  position: absolute !important;
  top: 14px !important;
  left: 82px !important;
  font-size: 1.4em !important;
  line-height: 1 !important;
  background: linear-gradient(90deg, #ff9de2, #c084fc, #818cf8, #7dd3fc, #6ee7b7, #fde68a, #fca5a5, #ff9de2) !important;
  background-size: 200% auto !important;
  -webkit-background-clip: text !important;
  -webkit-text-fill-color: transparent !important;
  background-clip: text !important;
  pointer-events: none !important;
  z-index: 10 !important;
  white-space: nowrap !important;
}

/* User name */
.mes[is_user="true"]::after {
  content: '✦ ' attr(ch_name) ' ✦' !important;
  left: auto !important;
  right: 85px !important;
  text-align: right !important;
  background: linear-gradient(90deg, #ff9de2, #c084fc, #818cf8, #7dd3fc, #6ee7b7, #fde68a, #fca5a5, #ff9de2) !important;
  background-size: 200% auto !important;
  -webkit-background-clip: text !important;
  -webkit-text-fill-color: transparent !important;
  background-clip: text !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   AVATARS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
@keyframes rainbowRing {
  0%   { box-shadow: 0 0 0 3px rgba(120, 60, 160, 0.9), 0 0 14px rgba(120, 60, 160, 0.5); }
  16%  { box-shadow: 0 0 0 3px rgba(80, 50, 150, 0.9), 0 0 14px rgba(80, 50, 150, 0.5); }
  33%  { box-shadow: 0 0 0 3px rgba(60, 30, 130, 0.9), 0 0 14px rgba(60, 30, 130, 0.5); }
  50%  { box-shadow: 0 0 0 3px rgba(40, 60, 140, 0.9), 0 0 14px rgba(40, 60, 140, 0.5); }
  66%  { box-shadow: 0 0 0 3px rgba(70, 40, 120, 0.9), 0 0 14px rgba(70, 40, 120, 0.5); }
  83%  { box-shadow: 0 0 0 3px rgba(100, 50, 155, 0.9), 0 0 14px rgba(100, 50, 155, 0.5); }
  100% { box-shadow: 0 0 0 3px rgba(120, 60, 160, 0.9), 0 0 14px rgba(120, 60, 160, 0.5); }
}

.mes .avatar,
.avatar img {
  animation: rainbowRing 9s linear infinite !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   TIMESTAMPS & METADATA
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
.mes[is_user="false"] .timestamp {
  margin-top: 20px !important;
  margin-left: 4px;
  color: rgba(155, 125, 205, 0.8) !important;
}
.mes[is_user="true"] .timestamp {
  margin-top: 20px !important;
  margin-right: 32px;
  color: rgba(205, 125, 165, 0.8) !important;
}
.mes .mesIDDisplay,
.mes .mes_timer,
.mes .tokenCounterDisplay {
  margin-top: 10px;
  color: rgba(145, 115, 185, 0.7) !important;
}
.mes .mesIDDisplay { margin-bottom: -10px; }
.mes .mes_timer { margin-bottom: -10px; }
.mes .tokenCounterDisplay {
  position: relative !important;
  top: 0px !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   MARKDOWN ELEMENTS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* In-chat headers */
.mes_text h1,
.mes_text h2,
.mes_text h3,
.mes_text h4 {
  width: fit-content !important;
  min-width: 80% !important;
  margin: 8px auto !important;
  padding: 6px 24px !important;
  clip-path: polygon(0 0, 100% 0, 97% 50%, 100% 100%, 0 100%, 3% 50%) !important;
}

h1, h2, h3, h4, .standoutHeader {
  background: linear-gradient(90deg, rgba(60, 30, 80, 0.95), rgba(40, 28, 85, 0.95), rgba(24, 40, 85, 0.95)) !important;
  color: #e1d7f5 !important;
  border-radius: 8px !important;
}

/* Horizontal rule */
.mes_text hr {
  border: none !important;
  height: 4px !important;
  background: linear-gradient(to right,
    transparent,
    rgba(248, 172, 210, 0.8),
    rgba(188, 172, 255, 0.8),
    rgba(158, 222, 210, 0.8),
    transparent
  ) !important;
  margin: 12px auto !important;
  width: 80% !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   BUTTONS & ICONS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
.mes_buttons button, .mes_buttons .fa-solid, .mes_buttons i {
  box-shadow: none !important;
  text-shadow: none !important;
  filter: none !important;
  color: #c084fc !important;
}
.mes_edit_buttons button {
  opacity: 1 !important;
  filter: none !important;
  background-color: rgba(55, 30, 85, 0.9) !important;
  border: 1px solid rgba(130, 100, 195, 0.8) !important;
  color: #e1d7f5 !important;
}
.mes_edit_buttons { filter: drop-shadow(0px 0px 0px transparent); }
.fa-solid { text-shadow: none !important; filter: none !important; box-shadow: none !important; }

.mes.smallSysMes::after {
  display: none !important;
}
.mes.smallSysMes {
   padding: 0px !important;
   padding-left: 0px !important;
}
div.custom-flex-container {
  margin-left: -20px !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   INPUT AREA
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
body #form_sheld {
  padding: 4px 0.5% 0 !important;
  border-top: 4px solid transparent !important;
  border-image: linear-gradient(to right, rgba(60, 30, 80, 1), rgba(40, 28, 85, 1), rgba(24, 40, 85, 1)) 1 !important;
  background: #0a0514 !important;
  background-color: #0a0514 !important;
}
#send_form {
  border: 1.5px solid rgba(130, 100, 195, 0.6) !important;
  border-radius: 20px !important;
  background: rgba(18, 10, 30, 0.97) !important;
  box-shadow: 0 2px 12px rgba(80, 50, 150, 0.25) !important;
}
#send_form:focus-within {
  border-color: rgba(175, 135, 240, 0.9) !important;
  box-shadow: 0 0 0 3px rgba(130, 100, 200, 0.2), 0 2px 12px rgba(80, 50, 150, 0.3) !important;
}
#send_textarea {
  min-height: 70px;
  color: #e1d7f5 !important;
}
select, .form-control, .ui-widget-content {
  background-color: rgba(28, 16, 48, 0.97) !important;
  color: #e1d7f5 !important;
}
input[type="text"], input[type="search"], input[type="number"],
textarea, .form-control {
  background-color: rgba(24, 14, 42, 0.97) !important;
  color: #e1d7f5 !important;
  border: 1px solid rgba(130, 100, 195, 0.5) !important;
}
#sheld {
  background-color: #0a0514 !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   TOP BAR
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
#top-bar {
  height: auto !important;
  min-height: 30px !important;
  box-shadow: none !important;
  border: none !important;
  margin-bottom: 0 !important;
  padding-bottom: 0 !important;
  background: linear-gradient(90deg,
    rgba(16, 8, 28, 0.99),
    rgba(20, 10, 34, 0.99)
  ) !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   SCROLLBAR
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
::-webkit-scrollbar { width: 10px; background: rgba(12, 6, 22, 0.95); }
::-webkit-scrollbar-thumb {
  background: linear-gradient(to bottom,
    rgba(60, 30, 80, 0.95) 0%,
    rgba(40, 28, 85, 0.95) 50%,
    rgba(24, 40, 85, 0.95) 100%
  );
  border: 3px solid rgba(20, 10, 35, 0.8);
  border-radius: 8px;
}
::-webkit-scrollbar-thumb:hover {
  background: linear-gradient(to bottom,
    rgba(90, 50, 120, 1) 0%,
    rgba(65, 48, 130, 1) 50%,
    rgba(40, 60, 130, 1) 100%
  );
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   DROPDOWNS & FORM ELEMENTS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
.select2-container .select2-selection {
  background-color: rgba(28, 16, 48, 0.97) !important;
  color: #e1d7f5 !important;
  border: 1px solid rgba(130, 100, 195, 0.6) !important;
}
.select2-container .select2-selection__rendered { color: #e1d7f5 !important; }
.select2-dropdown {
  background-color: rgba(20, 10, 36, 0.99) !important;
  border: 1px solid rgba(130, 100, 195, 0.6) !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   PROMPT MANAGER
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
#completion_prompt_manager_list { background-color: rgba(16, 8, 28, 0.97) !important; }
.completion_prompt_manager_header span { color: #e1d7f5 !important; text-shadow: none !important; filter: none !important; }
.completion_prompt_manager_header * { font-weight: bold !important; }
.completion_prompt_manager_prompt_disabled * {
  color: rgba(135, 105, 165, 0.75) !important;
  opacity: 1 !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   PANELS, EXTENSIONS & Z-INDEX
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */
#options { z-index: 5000 !important; }
#floatingPrompt, #cfgConfig, #SnippetsExtensionWindow, #WorldInfo {
  z-index: 4999 !important;
  max-width: 80vw !important;
  background: rgba(20, 10, 35, 0.99) !important;
  border: 1.5px solid rgba(130, 100, 195, 0.6) !important;
}
.drawer-content { margin-top: 0px !important; }
.floating_panel { max-width: 90vw !important; }
#WorldInfo { max-width: 85vw !important; max-height: 90vh !important; }
.world_entry .world_entry_form_control { width: 100% !important; }
#extensions_settings,
#extensions_settings2 {
  max-width: 90vw !important;
  background: rgba(20, 10, 35, 0.99) !important;
  color: #e1d7f5 !important;
}
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header {
  background: linear-gradient(90deg, rgba(60, 30, 80, 0.95), rgba(40, 28, 85, 0.95), rgba(24, 40, 85, 0.95)) !important;
  color: #e1d7f5 !important;
  border-radius: 8px !important;
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   CURSOR
